      "path": "src/modules/tasks/service.js",
      "content": "const projectsService = require('../projects/service');

const createTask = async (projectId, title) => {
  const project = projectsService.projectsStore.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = { id: projectsService.randomUUID(), title, status: 'todo' };
  project.tasks.push(task);
  return task;
};

const getAllTasks = async (projectId) => {
  const project = projectsService.projectsStore.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  return project.tasks;
};

const getDoneTasks = async (projectId) => {
  const project = projectsService.projectsStore.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  return project.tasks.filter(task => task.status === 'done');
};

const updateTaskStatus = async (projectId, taskId, status) => {
  const project = projectsService.projectsStore.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
};

module.exports = { createTask, getAllTasks, getDoneTasks, updateTaskStatus };
